import{_ as r,c as n}from"./app.0b00aae6.js";const o={},p=n('<h1 id="_32-\u8BB2-\u65E0\u5B9E\u4F8B\u65E0\u771F\u76F8-\u57FA\u4E8E-loadrunner-\u5B9E\u73B0\u4F01\u4E1A\u7EA7\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u5B9E\u8DF5-\u4E0A" tabindex="-1"><a class="header-anchor" href="#_32-\u8BB2-\u65E0\u5B9E\u4F8B\u65E0\u771F\u76F8-\u57FA\u4E8E-loadrunner-\u5B9E\u73B0\u4F01\u4E1A\u7EA7\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u5B9E\u8DF5-\u4E0A" aria-hidden="true">#</a> 32 \u8BB2\uFF1A\u65E0\u5B9E\u4F8B\u65E0\u771F\u76F8\uFF1A\u57FA\u4E8E LoadRunner \u5B9E\u73B0\u4F01\u4E1A\u7EA7\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u5B9E\u8DF5\uFF08\u4E0A\uFF09</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\u3002\u4ECA\u5929\u6211\u548C\u4F60\u5206\u4EAB\u7684\u4E3B\u9898\u662F\uFF1A\u65E0\u5B9E\u4F8B\u65E0\u771F\u76F8\u4E4B\u57FA\u4E8E LoadRunner \u5B9E\u73B0\u4F01\u4E1A\u7EA7\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u5B9E\u8DF5\uFF08\u4E0A\uFF09\u3002</p><p>\u4ECE\u4ECA\u5929\u5F00\u59CB\u7684\u4E24\u7BC7\u6587\u7AE0\uFF0C\u6211\u5C06\u4ECB\u7ECD\u5982\u4F55\u57FA\u4E8E LoadRunner \u5B9E\u9645\u5F00\u5C55\u4F01\u4E1A\u7EA7\u670D\u52A1\u5668\u7AEF\u7684\u6027\u80FD\u6D4B\u8BD5\u3002\u5206\u4EAB\u8FD9\u4E2A\u4E3B\u9898\u65F6\uFF0C\u6211\u4F1A\u4ECE\u6700\u5F00\u59CB\u7684\u6027\u80FD\u9700\u6C42\u83B7\u53D6\u5F00\u59CB\u8BB2\u8D77\uFF0C\u5E26\u4F60\u5B8C\u6574\u5730\u7ECF\u5386\u4E00\u4E2A\u5B9E\u9645\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u9879\u76EE\u3002\u901A\u8FC7\u8FD9\u4E2A\u8FC7\u7A0B\uFF0C\u6211\u5E0C\u671B\u53EF\u4EE5\u5E2E\u52A9\u4F60\u5FEB\u901F\u5EFA\u7ACB\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u5168\u5C40\u89C2\uFF0C\u5E76\u4E86\u89E3\u5404\u4E3B\u8981\u6B65\u9AA4\u7684\u5173\u952E\u6280\u672F\u7EC6\u8282\u3002</p><p>\u542C\u5230\u8FD9\u91CC\uFF0C\u4F60\u53EF\u80FD\u5C31\u6709\u4E9B\u56F0\u60D1\u4E86\u3002\u6211\u5728\u5206\u4EAB\u300A\u5DE5\u6B32\u5584\u5176\u4E8B\u5FC5\u5148\u5229\u5176\u5668\uFF1A\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u539F\u7406\u4E0E\u884C\u4E1A\u5E38\u7528\u5DE5\u5177\u7B80\u4ECB\u300B\u8FD9\u4E2A\u4E3B\u9898\u65F6\uFF0C\u66FE\u7ECF\u8BF4\u5230\uFF1ALoadRunner \u6BD4\u8F83\u9002\u5408\u4E8E\u4F20\u7EDF\u8F6F\u4EF6\u4F01\u4E1A\u5F00\u5C55\u6027\u80FD\u6D4B\u8BD5\uFF0C\u800C JMeter \u66F4\u9002\u7528\u4E8E\u4E92\u8054\u7F51\u4F01\u4E1A\u7684\u8F6F\u4EF6\u6027\u80FD\u6D4B\u8BD5\u3002\u90A3\u4E48\uFF0C\u4E3A\u4EC0\u4E48\u6211\u6CA1\u6709\u9009\u62E9\u4EE5 JMeter \u4E3A\u4F8B\u6765\u5C55\u5F00\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5462\uFF1F</p><p>\u6211\u9009\u62E9 LoadRunner\uFF0C\u662F\u7ECF\u8FC7\u6DF1\u601D\u719F\u8651\u7684\uFF0C\u4E3B\u8981\u539F\u56E0\u5305\u62EC\uFF1A</p><ol><li><strong>JMeter \u7684\u5B98\u65B9\u6587\u6863\u5BF9\u5176\u4F7F\u7528\u65B9\u6CD5\u4ECB\u7ECD\u5F97\u5F88\u8BE6\u7EC6\uFF0C\u800C\u4E14\u5176\u64CD\u4F5C\u57FA\u672C\u5C5E\u4E8E\u201C\u50BB\u74DC\u5F0F\u201D\u7684</strong>\u3002JMeter \u4F7F\u7528\u7684\u96BE\u70B9\u5728\u4E8E\uFF1A\u5982\u4F55\u652F\u6301\u6D77\u91CF\u5E76\u53D1\uFF0C\u4EE5\u53CA\u5B9E\u73B0\u66F4\u597D\u7684 load \u63A7\u5236\uFF0C\u89E3\u51B3\u8FD9\u4E2A\u95EE\u9898\u4F60\u53EF\u4EE5\u53C2\u8003 LoadRunner \u7684\u5B9E\u73B0\u65B9\u5F0F\uFF0C\u7136\u540E\u4ECE\u4F60\u6240\u5728\u4F01\u4E1A\u7684\u5B9E\u9645\u4E1A\u52A1\u573A\u666F\u51FA\u53D1\uFF0C\u8FDB\u884C\u4E8C\u6B21\u5F00\u53D1\u3002</li><li><strong>\u4E92\u8054\u7F51\u4F01\u4E1A\u548C\u4F20\u7EDF\u8F6F\u4EF6\u4F01\u4E1A\u7684\u8F6F\u4EF6\u4EA7\u54C1\u7684\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\uFF0C\u5728\u539F\u7406\u4EE5\u53CA\u57FA\u672C\u65B9\u6CD5\u4E0A\u662F\u57FA\u672C\u4E00\u81F4\u7684\uFF0C\u533A\u522B\u8F83\u5927\u7684\u53EA\u662F\u5168\u94FE\u8DEF\u538B\u6D4B</strong>\u3002\u6240\u4EE5\uFF0C\u6211\u4EE5\u4F20\u7EDF\u4F01\u4E1A\u7684\u8F6F\u4EF6\u4EA7\u54C1\u4E3A\u4F8B\u5C55\u5F00\u5206\u4EAB\uFF0C\u4F60\u56E0\u6B64\u5B66\u5230\u7684\u539F\u7406\u4EE5\u53CA\u6D4B\u8BD5\u65B9\u6CD5\u5C06\u540C\u6837\u9002\u7528\u4E8E\u4E92\u8054\u7F51\u8F6F\u4EF6\u4EA7\u54C1\u7684\u6027\u80FD\u6D4B\u8BD5\u3002</li><li><strong>\u5173\u4E8E\u4E92\u8054\u7F51\u8F6F\u4EF6\u4EA7\u54C1\u7684\u5168\u94FE\u8DEF\u538B\u6D4B\uFF0C\u7531\u4E8E\u9700\u8981\u5B9E\u73B0\u6D77\u91CF\u5E76\u53D1\u4EE5\u53CA\u6D41\u91CF\u9694\u79BB\u7B49\u64CD\u4F5C\uFF0C\u6240\u4EE5\u76EE\u524D\u53EA\u6709\u4E00\u4E9B\u5927\u578B\u4F01\u4E1A\u5728\u505A\uFF0C\u6BD4\u5982\u997F\u4E86\u4E48\u3001\u6DD8\u5B9D\u3001ebay\u3001\u7F8E\u56E2\u7B49\u8D85\u7EA7\u5927\u7684\u7F51\u7AD9</strong>\u3002\u4F46\u662F\uFF0C\u5982\u679C\u4F60\u4E5F\u60F3\u4E86\u89E3\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u8BDD\uFF0C\u6211\u4E5F\u4F1A\u51C6\u5907\u4E00\u7BC7\u201C\u52A0\u9910\u201D\u6587\u7AE0\uFF0C\u548C\u4F60\u5206\u4EAB\u5F00\u5C55\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u96BE\u70B9\uFF0C\u4EE5\u53CA\u5E94\u5BF9\u65B9\u6848\u3002\u6211\u4F1A\u66F4\u65B0\u5B8C\u6027\u80FD\u6D4B\u8BD5\u8FD9\u4E2A\u7CFB\u5217\u4EE5\u540E\uFF0C\u4E3A\u4F60\u51C6\u5907\u8FD9\u7BC7\u201C\u52A0\u9910\u201D\u6587\u7AE0\u3002</li></ol><p>\u4E3A\u4E86\u8BA9\u4F60\u5728\u8FDB\u884C\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u65F6\u66F4\u5145\u5206\u5730\u5229\u7528\u597D LoadRunner\uFF0C\u6240\u4EE5\u5728\u6B63\u5F0F\u5F00\u59CB\u8BB2\u89E3\u8FD9\u4E2A\u6D4B\u8BD5\u6848\u4F8B\u524D\uFF0C\u6211\u4F1A\u5148\u7ED9\u4F60\u7B80\u5355\u4ECB\u7ECD\u4E00\u4E0B LoadRunner \u7684\u57FA\u672C\u539F\u7406\uFF0C\u4EE5\u53CA\u4E3B\u8981\u7684\u529F\u80FD\u6A21\u5757\u3002\u8FD9\u4E9B\u529F\u80FD\u6A21\u5757\u4E0D\u4EC5\u5728\u8FD9\u4E2A\u6848\u4F8B\u4E2D\u4F1A\u7528\u5230\uFF0C\u4E5F\u4F1A\u5728\u5B9E\u9645\u5DE5\u7A0B\u9879\u76EE\u88AB\u7ECF\u5E38\u4F7F\u7528\uFF0C\u6240\u4EE5\u5982\u679C\u4F60\u6709\u4EC0\u4E48\u4E0D\u7406\u89E3\u7684\u5730\u65B9\uFF0C\u6B22\u8FCE\u7ED9\u6211\u7559\u8A00\u3002</p><p>** LoadRunner \u7684\u57FA\u672C\u539F\u7406**</p><p>\u4F60\u8FD8\u8BB0\u5F97\u6211\u5728\u300A\u5DE5\u6B32\u5584\u5176\u4E8B\u5FC5\u5148\u5229\u5176\u5668\uFF1A\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u539F\u7406\u4E0E\u884C\u4E1A\u5E38\u7528\u5DE5\u5177\u7B80\u4ECB\u300B\u8FD9\u4E2A\u4E3B\u9898\u4E2D\uFF0C\u4ECB\u7ECD\u8FC7\u7684\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u7684\u57FA\u672C\u539F\u7406\u5417\uFF1F</p><p>\u6211\u4EEC\u5148\u4E00\u8D77\u6765\u56DE\u5FC6\u4E00\u4E0B\u5427\uFF1A</p><p>\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u9996\u5148\u901A\u8FC7<strong>\u865A\u62DF\u7528\u6237\u811A\u672C\u751F\u6210\u5668</strong>\u751F\u6210\u57FA\u4E8E\u534F\u8BAE\u7684\u865A\u62DF\u7528\u6237\u811A\u672C\uFF0C\u7136\u540E\u6839\u636E\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u8BBE\u8BA1\u7684\u8981\u6C42\uFF0C\u901A\u8FC7<strong>\u538B\u529B\u63A7\u5236\u5668</strong>\u63A7\u5236\u534F\u8C03\u5404\u4E2A<strong>\u538B\u529B\u4EA7\u751F\u5668</strong>\u4EE5\u5E76\u53D1\u7684\u65B9\u5F0F\u6267\u884C\u865A\u62DF\u7528\u6237\u811A\u672C\uFF0C\u5E76\u4E14\u5728\u6D4B\u8BD5\u6267\u884C\u8FC7\u7A0B\u4E2D\uFF0C\u901A\u8FC7<strong>\u7CFB\u7EDF\u76D1\u63A7\u5668</strong>\u6536\u96C6\u5404\u79CD\u6027\u80FD\u6307\u6807\u4EE5\u53CA\u7CFB\u7EDF\u8D44\u6E90\u5360\u7528\u7387\uFF0C\u6700\u540E\u901A\u8FC7<strong>\u6D4B\u8BD5\u7ED3\u679C\u5206\u6790\u5668</strong>\u5C55\u793A\u6D4B\u8BD5\u7ED3\u679C\u6570\u636E\u3002</p><p>LoadRunner \u7684\u57FA\u672C\u539F\u7406\uFF0C\u4E0E\u4E0A\u9762\u7684\u63CF\u8FF0\u5B8C\u5168\u4E00\u81F4\u3002\u5728 LoadRunner \u4E2D\uFF0CVirtual UserGenerator \u5BF9\u5E94\u7684\u5C31\u662F\u865A\u62DF\u7528\u6237\u811A\u672C\u751F\u6210\u5668\uFF0CController</p><p>\u5BF9\u5E94\u7684\u5C31\u662F\u538B\u529B\u63A7\u5236\u5668\u548C\u7CFB\u7EDF\u76D1\u63A7\u5668\uFF0CLoad Generator \u5BF9\u5E94\u7684\u5C31\u662F\u538B\u529B\u4EA7\u751F\u5668\uFF0CAnalysis \u5BF9\u5E94\u7684\u5C31\u662F\u6D4B\u8BD5\u7ED3\u679C\u5206\u6790\u5668\u3002</p><p>\u4E3A\u4E86\u5E2E\u52A9\u4F60\u7406\u89E3 LoadRunner \u7684\u5DE5\u4F5C\u539F\u7406\u548C\u6A21\u5757\uFF0C\u5148\u6487\u5F00\u8FD9\u4E9B\u540D\u8BCD\u4E0D\u8C08\uFF0C\u8BBE\u60F3\u4E00\u4E0B\u5982\u679C\u6CA1\u6709\u4E13\u7528\u7684\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\uFF0C\u6211\u4EEC\u5982\u4F55\u5F00\u5C55\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u3002</p><p>\u5176\u5B9E\uFF0C\u201C\u4EBA\u8089\u201D\u5F00\u5C55\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u4E5F\u4E0D\u7B97\u592A\u96BE\u3002\u8FD9\u4E2A\u8FC7\u7A0B\u5927\u81F4\u662F\u8FD9\u6837\u7684\uFF1A</p><ul><li>\u9996\u5148\uFF0C\u6211\u4EEC\u9700\u8981\u4E00\u6279\u6D4B\u8BD5\u673A\u5668\uFF0C\u6BCF\u53F0\u6D4B\u8BD5\u673A\u5668\u96C7\u4F63\u4E00\u4E2A\u6D4B\u8BD5\u4EBA\u5458\uFF1B</li><li>\u7136\u540E\uFF0C\u6211\u4EEC\u9700\u8981\u4E00\u4E2A\u534F\u8C03\u5458\u62FF\u7740\u8BDD\u7B52\u53D1\u53F7\u65BD\u4EE4\uFF0C\u7EDF\u4E00\u63A7\u5236\u8FD9\u4E9B\u6D4B\u8BD5\u4EBA\u5458\u7684\u6B65\u8C03\uFF0C\u534F\u8C03\u5458\u4F1A\u5411\u6240\u6709\u6D4B\u8BD5\u4EBA\u5458\u558A\u8BDD\uFF0C\u6BD4\u5982\u201C1 \u53F7\u5230 100 \u53F7\u6D4B\u8BD5\u4EBA\u5458\u73B0\u5728\u5F00\u59CB\u6267\u884C\u767B\u5F55\u64CD\u4F5C\uFF0C100 \u53F7\u5230 1000 \u53F7\u6D4B\u8BD5\u4EBA\u5458 5 \u5206\u949F\u540E\u5F00\u59CB\u6267\u884C\u641C\u7D22\u64CD\u4F5C\u201D\uFF0C\u540C\u65F6\u534F\u8C03\u5458\u8FD8\u4F1A\u8981\u6C42\u6BCF\u4E2A\u6D4B\u8BD5\u4EBA\u5458\u8BB0\u5F55\u64CD\u4F5C\u82B1\u8D39\u7684\u65F6\u95F4\uFF1B</li><li>\u6D4B\u8BD5\u5B8C\u6210\u540E\uFF0C\u6D4B\u8BD5\u534F\u8C03\u5458\u4F1A\u8981\u6C42\u6027\u80FD\u5DE5\u7A0B\u5E08\u5206\u6790\u6D4B\u8BD5\u8FC7\u7A0B\u4E2D\u8BB0\u5F55\u7684\u6570\u636E\u3002</li></ul><p>\u8FD9\u4E2A\u8FC7\u7A0B\uFF0C\u5982\u56FE 1 \u6240\u793A\u3002</p><p><img src="https://static001.geekbang.org/resource/image/d9/43/d96d730ea9b63a9371149465af9d3143.png" alt="\u5982\u679C\u6CA1\u6709\u4E13\u7528\u7684\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\uFF0C\u5982\u4F55\u201C\u4EBA\u8089\u201D\u5F00\u5C55\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5"></p><p>\u7406\u89E3\u4E86\u8FD9\u79CD\u201C\u4EBA\u8089\u201D\u6A21\u5F0F\u7684\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u540E\uFF0C\u6211\u4EEC\u518D\u56DE\u8FC7\u5934\u6765\u770B LoadRunner \u7684\u5404\u4E2A\u6A21\u5757\u5C31\u8C41\u7136\u5F00\u6717\u4E86\u3002</p><ul><li>\u6D4B\u8BD5\u534F\u8C03\u5458\u4EE5\u53CA\u5B8C\u6210\u6570\u636E\u8BB0\u5F55\u7684\u90E8\u5206\u5C31\u662F Controller \u6A21\u5757\uFF1B</li><li>\u5927\u91CF\u7684\u6D4B\u8BD5\u673A\u5668\u4EE5\u53CA\u64CD\u4F5C\u8FD9\u4E9B\u6D4B\u8BD5\u673A\u5668\u7684\u4EBA\u5C31\u662F Load Generator \u6A21\u5757\uFF1B</li><li>\u64CD\u4F5C\u8FD9\u4E9B\u6D4B\u8BD5\u673A\u5668\u7684\u4EBA\u7684\u884C\u4E3A\u5C31\u662F Virtual User Generator \u4EA7\u751F\u7684\u865A\u62DF\u7528\u6237\u811A\u672C\uFF1B</li><li>\u5BF9\u6D4B\u8BD5\u6570\u636E\u7684\u5206\u6790\u5C31\u662F Analysis \u6A21\u5757\u3002</li></ul><p><strong>LoadRunner \u7684\u4E3B\u8981\u6A21\u5757</strong></p><p>\u901A\u8FC7\u5BF9\u201C\u4EBA\u8089\u201D\u6A21\u5F0F\u548C LoadRunner \u5DE5\u5177\u7684\u7C7B\u6BD4\uFF0C\u6211\u4EEC\u53EF\u4EE5\u5F88\u6E05\u695A\u7684\u770B\u5230\uFF0C\u4F7F\u7528 LoadRunner \u8FDB\u884C\u6027\u80FD\u6D4B\u8BD5\uFF0C\u4E3B\u8981\u9700\u8981 Virtual User Generator\u3001Controller\uFF08\u8FD9\u4E2A\u6A21\u5757\u5305\u542B\u4E86 Load Generator\uFF09\uFF0C\u4EE5\u53CA Analysis \u8FD9\u4E09\u5927\u6A21\u5757\u7EC4\u5408\u4F7F\u7528\u3002\u63A5\u4E0B\u6765\uFF0C\u6211\u518D\u548C\u4F60\u8BE6\u7EC6\u804A\u804A\u8FD9\u4E09\u5927\u6A21\u5757\u7684\u4F5C\u7528\uFF0C\u4EE5\u53CA\u9700\u8981\u6CE8\u610F\u7684\u95EE\u9898\u3002</p><p><strong>\u7B2C\u4E00\uFF0CVirtual User Generator</strong></p><p>Virtual User Generator\uFF0C\u7528\u4E8E\u751F\u6210\u6A21\u62DF\u7528\u6237\u884C\u4E3A\u7684\u6D4B\u8BD5\u811A\u672C\uFF0C\u751F\u6210\u7684\u624B\u6BB5\u4E3B\u8981\u662F\u57FA\u4E8E\u534F\u8BAE\u7684\u5F55\u5236\uFF0C\u4E5F\u5C31\u662F\u7531\u6027\u80FD\u6D4B\u8BD5\u811A\u672C\u5F00\u53D1\u4EBA\u5458\u5728\u901A\u8FC7 GUI \u6267\u884C\u4E1A\u52A1\u64CD\u4F5C\u7684\u540C\u65F6\uFF0C\u5F55\u5236\u5BA2\u6237\u7AEF\u548C\u670D\u52A1\u5668\u4E4B\u95F4\u7684\u901A\u4FE1\u534F\u8BAE\uFF0C\u5E76\u6700\u7EC8\u8F6C\u5316\u4E3A\u4EE3\u7801\u5316\u7684 LoadRunner \u7684\u865A\u62DF\u7528\u6237\u811A\u672C\u3002</p><p>\u8FD9\u6837\u8F6C\u5316\u5F97\u5230\u7684\u865A\u62DF\u811A\u672C\u5F80\u5F80\u5E76\u4E0D\u80FD\u88AB\u76F4\u63A5\u4F7F\u7528\uFF0C\u8FD8\u9700\u8981\u7ECF\u5386\u6570\u636E\u53C2\u6570\u5316\uFF08Parameterization\uFF09\u3001\u5173\u8054\u5EFA\u7ACB\uFF08Correlation\uFF09\uFF0C\u4EE5\u53CA\u8FD0\u884C\u65F6\u8BBE\u7F6E\uFF08Run Time Settings\uFF09\u7B49\u64CD\u4F5C\uFF0C\u7136\u540E\u624D\u80FD\u7528\u4E8E\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u4E2D\u3002</p><p>\u5177\u4F53\u4EC0\u4E48\u662F\u6570\u636E\u53C2\u6570\u5316\u3001\u4EC0\u4E48\u662F\u5173\u8054\u5EFA\u7ACB\u3001\u8FD0\u884C\u65F6\u8BBE\u7F6E\u90FD\u6709\u54EA\u4E9B\u53EF\u9009\u9879\uFF0C\u6211\u4F1A\u5728\u5206\u4EAB\u5B9E\u4F8B\u65F6\u518D\u8BE6\u7EC6\u5C55\u5F00\u3002</p><p><strong>\u7B2C\u4E8C\uFF0CLoadRunner Controller</strong></p><p>Controller \u76F8\u5F53\u4E8E\u6027\u80FD\u6D4B\u8BD5\u6267\u884C\u7684\u63A7\u5236\u7BA1\u7406\u4E2D\u5FC3\uFF0C\u8D1F\u8D23\u63A7\u5236 Load Generator \u4EA7\u751F\u6D4B\u8BD5\u8D1F\u8F7D\uFF0C\u4EE5\u6267\u884C\u9884\u5148\u8BBE\u5B9A\u597D\u7684\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\uFF1B\u540C\u65F6\uFF0C\u5B83\u8FD8\u8D1F\u8D23\u6536\u96C6\u5404\u7C7B\u76D1\u63A7\u6570\u636E\u3002</p><p>\u5728\u5B9E\u9645\u6267\u884C\u6027\u80FD\u6D4B\u8BD5\u65F6\uFF0CController \u662F\u548C\u6027\u80FD\u5DE5\u7A0B\u5E08\u6253\u4EA4\u9053\u6700\u591A\u7684\u6A21\u5757\uFF0C\u6027\u80FD\u5DE5\u7A0B\u5E08\u4F1A\u5728 Controller \u7684 UI \u754C\u9762\u4E0A\u5B8C\u6210\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u7684\u8BBE\u8BA1\u3001\u8FD0\u884C\u65F6\u7684\u5B9E\u65F6\u76D1\u63A7\u3001\u6D4B\u8BD5\u8D1F\u8F7D\u7684\u5F00\u59CB\u4E0E\u7ED3\u675F\u7B49\u64CD\u4F5C\u3002</p><p><strong>\u7B2C\u4E09\uFF0CLoadRunner Analysis</strong></p><p>Analysis \u662F LoadRunner \u4E2D\u4E00\u4E2A\u5F3A\u5927\u7684\u5206\u6790\u63D2\u4EF6\u3002\u5B83\u4E0D\u4EC5\u80FD\u56FE\u5F62\u5316\u5C55\u793A\u6D4B\u8BD5\u8FC7\u7A0B\u4E2D\u6536\u96C6\u7684\u6570\u636E\uFF0C\u8FD8\u80FD\u5F88\u65B9\u4FBF\u5730\u5BF9\u591A\u4E2A\u6307\u6807\u505A\u5173\u8054\u5206\u6790\uFF0C\u627E\u51FA\u5B83\u4EEC\u4E4B\u95F4\u7684\u56E0\u679C\u5173\u7CFB\u3002\u5B83\u6700\u6839\u672C\u7684\u76EE\u7684\u5C31\u662F\uFF0C\u5206\u6790\u51FA\u7CFB\u7EDF\u53EF\u80FD\u7684\u6027\u80FD\u74F6\u9888\u70B9\u4EE5\u53CA\u6F5C\u5728\u7684\u6027\u80FD\u95EE\u9898\u3002</p><p>\u73B0\u5728\uFF0C\u4F60\u5DF2\u7ECF\u4E86\u89E3\u4E86 LoadRunner \u7684\u539F\u7406\u548C\u5404\u4E2A\u6A21\u5757\u4E86\uFF0C\u63A5\u4E0B\u6765\u6211\u4EEC\u5C31\u5F00\u59CB\u5B9E\u6218\u5427\u3002\u901A\u8FC7\u8FD9\u4E2A\u5B9E\u6218\uFF0C\u6211\u5E0C\u671B\u4F60\u53EF\u4EE5\u638C\u63E1\u5982\u4F55\u57FA\u4E8E LoadRunner \u8FDB\u884C\u4F01\u4E1A\u7EA7\u7684\u6027\u80FD\u6D4B\u8BD5\u3002</p><p>\u4ECE\u5B8F\u89C2\u89D2\u5EA6\u6765\u8BB2\uFF0C\u57FA\u4E8E LoadRunner \u5B8C\u6210\u4F01\u4E1A\u7EA7\u6027\u80FD\u6D4B\u8BD5\uFF0C\u53EF\u4EE5\u5212\u5206\u4E3A\u4E94\u4E2A\u9636\u6BB5\uFF1A</p><ol><li>\u6027\u80FD\u9700\u6C42\u6536\u96C6\u4EE5\u53CA\u8D1F\u8F7D\u8BA1\u5212\u5236\u5B9A\uFF1B</li><li>\u5F55\u5236\u5E76\u589E\u5F3A\u865A\u62DF\u7528\u6237\u811A\u672C\uFF1B</li><li>\u521B\u5EFA\u5E76\u5B9A\u4E49\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\uFF1B</li><li>\u6267\u884C\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\uFF1B</li><li>\u5206\u6790\u6D4B\u8BD5\u62A5\u544A\u3002</li></ol><p>\u56FE 2 \u6E05\u6670\u5730\u63CF\u8FF0\u4E86\u8FD9 5 \u4E2A\u9636\u6BB5\u7684\u5148\u540E\u987A\u5E8F\uFF0C\u4EE5\u53CA\u9700\u8981 LoadRunner \u5404\u6A21\u5757\u53D1\u6325\u4F5C\u7528\u7684\u90E8\u5206\u3002\u63A5\u4E0B\u6765\uFF0C\u6211\u548C\u4F60\u8BE6\u7EC6\u804A\u804A\u6BCF\u4E2A\u9636\u6BB5\u7684\u5177\u4F53\u5DE5\u4F5C\uFF0C\u4EE5\u53CA\u5173\u952E\u7684\u6280\u672F\u7EC6\u8282\u3002</p><p><img src="https://static001.geekbang.org/resource/image/e8/94/e8e58ca14e80346be38291cf84bf2394.png" alt="\u4F7F\u7528LoadRunner\u5B8C\u6210\u4F01\u4E1A\u7EA7\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u5178\u578B\u6D41\u7A0B\u4E0E\u6B65\u9AA4"></p><p><strong>\u9636\u6BB5 1\uFF1A\u6027\u80FD\u9700\u6C42\u6536\u96C6\u4EE5\u53CA\u8D1F\u8F7D\u8BA1\u5212\u5236\u5B9A</strong></p><p>\u5176\u5B9E\uFF0C\u65E0\u8BBA\u662F\u8FDB\u884C\u4EC0\u4E48\u7C7B\u578B\u7684\u6D4B\u8BD5\uFF0C\u4F60\u7684\u7B2C\u4E00\u6B65\u5DE5\u4F5C\u90FD\u662F\u8981\u6839\u636E\u6D4B\u8BD5\u76EE\u7684\u660E\u786E\u6D4B\u8BD5\u7684\u5177\u4F53\u9700\u6C42\u3002\u4F01\u4E1A\u7EA7\u7684\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\uFF0C\u5F53\u7136\u4E5F\u4E0D\u4F8B\u5916\u3002</p><p>\u4E00\u822C\u60C5\u51B5\u4E0B\uFF0C\u4F01\u4E1A\u7EA7\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u5177\u4F53\u9700\u6C42\uFF0C\u4E3B\u8981\u5305\u542B\u4EE5\u4E0B\u5185\u5BB9\uFF1A</p><ul><li><strong>\u7CFB\u7EDF\u6574\u4F53\u7684\u5E76\u53D1\u7528\u6237\u6570</strong>\u3002\u6BD4\u5982\uFF0C\u9AD8\u5CF0\u65F6\u6BB5\u4F1A\u6709 10 \u4E07\u7528\u6237\u540C\u65F6\u5728\u7EBF\uFF1B</li><li><strong>\u5E76\u53D1\u7528\u6237\u4E1A\u52A1\u64CD\u4F5C\u7684\u5206\u5E03\u60C5\u51B5</strong>\u3002\u6BD4\u5982\uFF0C20%\u7684\u7528\u6237\u5728\u505A\u767B\u5F55\u64CD\u4F5C\uFF0C30%\u7684\u7528\u6237\u5728\u505A\u8BA2\u5355\u64CD\u4F5C\uFF0C\u5176\u4ED6 50%\u7684\u7528\u6237\u5728\u505A\u641C\u7D22\u64CD\u4F5C\uFF1B</li><li><strong>\u5355\u4E00\u4E1A\u52A1\u64CD\u4F5C\u7684\u7528\u6237\u884C\u4E3A\u6A21\u5F0F</strong>\u3002\u6BD4\u5982\uFF0C\u4E24\u4E2A\u64CD\u4F5C\u4E4B\u95F4\u7684\u5178\u578B\u505C\u7559\u65F6\u95F4\uFF0C\u5B8C\u6210\u540C\u4E00\u4E1A\u52A1\u7684\u4E0D\u540C\u64CD\u4F5C\u8DEF\u5F84\u7B49\uFF1B</li><li><strong>\u5E76\u53D1\u7528\u6237\u9AD8\u5CF0\u671F\u7684\u65F6\u95F4\u5206\u5E03\u89C4\u5F8B</strong>\u3002\u6BD4\u5982\uFF0C\u65E9\u4E0A 8 \u70B9\u4F1A\u6709\u5927\u91CF\u7528\u6237\u767B\u5F55\u7CFB\u7EDF\uFF0C\u665A\u4E0A 6 \u70B9\u540E\u7528\u6237\u9010\u6E10\u9000\u51FA\uFF1B</li><li><strong>\u8FBE\u5230\u6700\u9AD8\u5CF0\u8D1F\u8F7D\u7684\u65F6\u95F4\u957F\u5EA6</strong>\u3002\u6BD4\u5982\uFF0C\u5E76\u53D1\u7528\u6237\u4ECE 0 \u589E\u957F\u5230 10 \u4E07\u82B1\u8D39\u7684\u603B\u65F6\u95F4\uFF1B</li><li>\u2026 \u5B8C\u6210\u8FD9\u4E9B\u70B9\u7684\u6D4B\u8BD5\uFF0C\u5176\u5B9E\u5E76\u4E0D\u590D\u6742\u3002\u4F60\u53EA\u8981\u6309\u7167\u8FD9\u4E2A\u5DF2\u7ECF\u660E\u786E\u7684\u9700\u6C42\uFF0C\u5F00\u53D1\u540E\u7EED\u7684\u6D4B\u8BD5\u811A\u672C\u3001\u8BBE\u8BA1\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u5C31\u53EF\u4EE5\u4E86\u3002</li></ul><p>\u4F46\u662F\uFF0C\u5982\u679C\u4F60\u60F3\u8981\u6210\u957F\u4E3A\u66F4\u8D44\u6DF1\u7684\u6027\u80FD\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\uFF0C\u6216\u8005\u5DF2\u7ECF\u662F\u6027\u80FD\u6D4B\u8BD5\u7684\u8BBE\u8BA1\u8005\u3001\u8D44\u6DF1\u7684\u6027\u80FD\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u4E86\uFF0C\u90A3\u4E48\u4F60\u5C31\u9700\u8981\u5168\u7A0B\u53C2\u4E0E\u5230\u8FD9\u4E9B\u9700\u6C42\u7684\u83B7\u53D6\u548C\u786E\u5B9A\u4E2D\u3002</p><p>\u5176\u5B9E\uFF0C\u5728\u6211\u770B\u6765\uFF0C\u83B7\u53D6\u8FD9\u4E9B\u6D4B\u8BD5\u9700\u6C42\u65F6\u6027\u80FD\u6D4B\u8BD5\u4E2D\u6700\u96BE\u7684\u4E24\u4E2A\u5DE5\u4F5C\u4E4B\u4E00\u3002\u53E6\u4E00\u4E2A\u6700\u96BE\u7684\u5DE5\u4F5C\u662F\uFF0C\u6D4B\u8BD5\u7ED3\u679C\u5206\u6790\u4E0E\u6027\u80FD\u95EE\u9898\u5B9A\u4F4D\u3002\u800C\u5176\u4ED6\u7C7B\u4F3C\u6027\u80FD\u6D4B\u8BD5\u811A\u672C\u5F00\u53D1\u3001\u573A\u666F\u8BBE\u8BA1\u7B49\u5DE5\u4F5C\u770B\u8D77\u6765\u5F88\u6709\u6280\u672F\u542B\u91CF\uFF0C\u4F46\u5B9E\u9645\u90FD\u662F\u4E00\u4E9B\u76F8\u5BF9\u673A\u68B0\u6027\u7684\u91CD\u590D\u5DE5\u4F5C\u3002</p><p>\u90A3\u4E3A\u4EC0\u4E48\u83B7\u53D6\u6D4B\u8BD5\u9700\u6C42\u96BE\u505A\u5462\uFF1F\u56E0\u4E3A\u7EDD\u5927\u591A\u6570\u60C5\u51B5\u4E0B\u6CA1\u4EBA\u4F1A\u660E\u786E\u544A\u8BC9\u4F60\u5177\u4F53\u7684\u6027\u80FD\u9700\u6C42\u3002</p><p>\u5BF9\u4E8E\u8F6F\u4EF6\u7684\u529F\u80FD\u6D4B\u8BD5\u6765\u8BF4\uFF0C\u5982\u679C\u9700\u6C42\u4E0D\u660E\u786E\uFF0C\u4F60\u53EF\u4EE5\u76F4\u63A5\u6C42\u52A9\u4E8E\u4EA7\u54C1\u7ECF\u7406\u3002</p><p>\u800C\u5BF9\u6027\u80FD\u6D4B\u8BD5\u9700\u6C42\u6765\u8BB2\uFF0C\u4EA7\u54C1\u7ECF\u7406\u901A\u5E38\u65E0\u6CD5\u51C6\u786E\u544A\u8BC9\u4F60\u7528\u6237\u7684\u5404\u4E2A\u4E1A\u52A1\u64CD\u4F5C\u6240\u5360\u7684\u767E\u5206\u6BD4\uFF0C\u4E5F\u65E0\u6CD5\u544A\u8BC9\u4F60\u51C6\u786E\u7684\u7528\u6237\u884C\u4E3A\u6A21\u5F0F\u3002\u4EA7\u54C1\u7ECF\u7406\u80FD\u505A\u7684\uFF0C\u5F80\u5F80\u662F\u7ED9\u51FA\u5B9A\u6027\u63CF\u8FF0\uFF0C\u7136\u540E\u9700\u8981\u4F60\u53BB\u8BA1\u7B97\u6216\u8005\u6839\u636E\u8FC7\u5F80\u7ECF\u9A8C\u5F97\u5230\u5177\u4F53\u7684\u5B9A\u91CF\u9700\u6C42\u3002\u6240\u4EE5\uFF0C\u6211\u4EEC\u7ECF\u5E38\u4F1A\u542C\u5230\u4EA7\u54C1\u7ECF\u7406\u5BF9\u6027\u80FD\u6D4B\u8BD5\u4EBA\u5458\u8BF4\uFF1A\u201C\u4F60\u662F\u6027\u80FD\u4E13\u5BB6\uFF0C\u4F60\u6765\u544A\u8BC9\u6211\u6027\u80FD\u9700\u6C42\u201D\u3002</p><p>\u90A3\u4E48\uFF0C\u5BF9\u4E8E\u6027\u80FD\u6D4B\u8BD5\u8BBE\u8BA1\u4EBA\u5458\u6765\u8BF4\uFF0C\u5230\u5E95\u5982\u4F55\u83B7\u5F97\u8FD9\u4E2A\u660E\u786E\u7684\u6027\u80FD\u9700\u6C42\u5462\uFF1F\u8BF4\u5230\u8FD9\u91CC\uFF0C\u4F60\u5E94\u8BE5\u660E\u767D\u4E86\u8FD9\u662F\u4E00\u4E2A\u975E\u5E38\u590D\u6742\u7684\u8BDD\u9898\uFF0C\u56E0\u4E3A\u6D4B\u8BD5\u76EE\u7684\u4E0D\u540C\uFF0C\u6240\u7528\u7684\u65B9\u6CD5\u4E5F\u5404\u4E0D\u76F8\u540C\u3002\u6240\u4EE5\uFF0C\u5728\u8FD9\u6B21\u5206\u4EAB\u4E2D\uFF0C\u6211\u4E5F\u53EA\u662F\u53EF\u4EE5\u7ED9\u4F60\u51C6\u5907\u4E00\u4E2A\u5B9E\u9645\u7684\u6D4B\u8BD5\u6848\u4F8B\uFF0C\u548C\u4F60\u5206\u4EAB\u83B7\u53D6\u5177\u4F53\u6D4B\u8BD5\u9700\u6C42\u7684\u601D\u8003\u65B9\u5F0F\u3002</p><p>\u8FD8\u8BB0\u5F97\u6211\u5728\u7B2C 29 \u7BC7\u6587\u7AE0\u300A\u804A\u804A\u6027\u80FD\u6D4B\u8BD5\u7684\u57FA\u672C\u65B9\u6CD5\u4E0E\u5E94\u7528\u9886\u57DF\u300B\u4E2D\u4ECB\u7ECD\u7684\u533B\u9662\u4F53\u68C0\u7684\u4F8B\u5B50\u5417\uFF1F\u5047\u8BBE\uFF0C\u4EA7\u54C1\u7ECF\u7406\u5BF9\u533B\u9662\u4F53\u68C0\u7684\u6027\u80FD\u8981\u6C42\u662F\u201C\u6BCF\u5929\u652F\u6301\u5B8C\u6210 8000 \u4E2A\u4F53\u68C0\u201D\uFF0C\u8FD9\u4E2A\u9700\u6C42\u770B\u4F3C\u5F88\u5177\u4F53\uFF0C\u4F46\u662F\u8981\u8F6C\u5316\u6210\u5B9E\u9645\u53EF\u64CD\u4F5C\u7684\u6027\u80FD\u6D4B\u8BD5\u9700\u6C42\uFF0C\u8FD8\u9700\u8981\u518D\u7EC6\u5316\u3002</p><p><strong>\u9996\u5148\uFF0C\u4F60\u8981\u660E\u786E\u8FD9\u91CC\u7684\u201C\u6BCF\u5929\u201D\u662F\u5426\u6307\u7684\u662F 24 \u5C0F\u65F6</strong>\u3002\u663E\u7136\uFF0C\u8FD9\u53D6\u51B3\u4E8E\u4EA7\u54C1\u672C\u8EAB\u7684\u5C5E\u6027\u3002\u6BD4\u5982\uFF0C\u4EA7\u54C1\u662F\u4E3A\u5355\u4E00\u65F6\u533A\u7684\u7528\u6237\u63D0\u4F9B\u670D\u52A1\uFF0C\u8FD8\u662F\u8981\u9762\u5411\u5168\u7403\u6240\u6709\u65F6\u533A\u7684\u7528\u6237\u3002\u90A3\u4E48\uFF0C\u6839\u636E\u4F53\u68C0\u4E2D\u5FC3\u7684\u5C5E\u6027\uFF0C\u4F60\u5F88\u5BB9\u6613\u5C31\u53EF\u4EE5\u786E\u5B9A\u201C\u6BCF\u5929\u201D\u4E00\u5B9A\u662F\u6307 8 \u5C0F\u65F6\u7684\u5DE5\u4F5C\u65F6\u95F4\u3002\u56E0\u4E3A\uFF0C\u4F53\u68C0\u4E2D\u5FC3\u4E00\u5B9A\u662F\u5728\u4E00\u4E2A\u786E\u5B9A\u7684\u65F6\u533A\uFF0C\u5E76\u4E14\u4E0D\u4F1A 24 \u5C0F\u65F6\u8425\u4E1A\u3002</p><p><strong>\u7136\u540E\uFF0C\u4F60\u660E\u786E\u4E86\u8FD9\u4E2A 8 \u5C0F\u65F6\u540E\uFF0C\u90A3\u4E48\u539F\u59CB\u9700\u6C42\u662F\u4E0D\u662F\u53EF\u4EE5\u8F6C\u5316\u4E3A\u201C\u6BCF\u5C0F\u65F6\u652F\u6301\u5B8C\u6210 1000 \u4E2A\u4F53\u68C0\u201D\uFF1F</strong></p><p>\u5982\u679C\u6309\u7167\u8FD9\u4E2A\u5957\u8DEF\u8BBE\u8BA1\u540E\u7EED\u7684\u6027\u80FD\u6D4B\u8BD5\u7684\u8BDD\uFF0C\u4F60\u4F1A\u53D1\u73B0\u5373\u4F7F\u6D4B\u8BD5\u987A\u5229\u5B8C\u6210\uFF0C\u5E76\u4E14\u5404\u9879\u6027\u80FD\u6307\u6807\u90FD\u8FBE\u6807\u4E86\uFF0C\u4F46\u662F\u4E00\u65E6\u4E0A\u7EBF\u540E\uFF0C\u7CFB\u7EDF\u8FD8\u662F\u5F88\u6709\u53EF\u80FD\u88AB\u538B\u57AE\u3002\u56E0\u4E3A\u5B9E\u9645\u60C5\u51B5\u662F\uFF0C\u9A8C\u8840\u5F80\u5F80\u9700\u8981\u7A7A\u8179\uFF0C\u6240\u4EE5\u4E0A\u5348\u5F80\u5F80\u662F\u4F53\u68C0\u4E2D\u5FC3\u7684\u9AD8\u5CF0\u65F6\u6BB5\uFF0C\u4F53\u68C0\u8005\u4F1A\u5728\u4E0A\u5348\u96C6\u4E2D\u6D8C\u5165\u4F53\u68C0\u4E2D\u5FC3\u3002\u4E5F\u5C31\u662F\u8BF4\uFF0C\u8FD9 8000 \u4E2A\u4F53\u68C0\u5E76\u4E0D\u662F\u5E73\u5747\u5206\u5E03\u5728 8 \u5C0F\u65F6\u5185\u5B8C\u6210\u7684\uFF0C\u800C\u662F\u6709\u660E\u663E\u7684\u9AD8\u5CF0\u65F6\u6BB5\u3002</p><p><strong>\u6700\u540E\uFF0C\u4F60\u53EF\u4EE5\u91C7\u7528 80/20 \u539F\u5219\u5BF9\u9AD8\u5CF0\u65F6\u6BB5\u7684\u7528\u6237\u8D1F\u8F7D\u8FDB\u884C\u5EFA\u6A21</strong>\uFF0C\u6BD4\u5982 80%\u7684\u4F53\u68C0\uFF086400 \u4E2A\uFF09\u662F\u53D1\u751F\u5728\u4E0A\u5348 20%\u7684\u65F6\u95F4\uFF0896 \u5206\u949F\uFF09\u91CC\u3002\u5F53\u7136\uFF0C\u4E3A\u4E86\u4F7F\u6A21\u578B\u66F4\u63A5\u8FD1\u771F\u5B9E\u7684\u60C5\u51B5\uFF0C\u4F60\u8FD8\u5E94\u8BE5\u5206\u6790\u5386\u53F2\u6570\u636E\uFF0C\u7136\u540E\u5BF9\u8BE5\u6A21\u578B\u505A\u8FDB\u4E00\u6B65\u7684\u4FEE\u6B63\uFF0C\u8FD9\u4E5F\u662F\u76EE\u524D\u88AB\u666E\u904D\u91C7\u7528\u7684\u65B9\u6CD5\u3002</p><p>\u53E6\u5916\uFF0C\u5728\u5F97\u5230\u4E86\u8D1F\u8F7D\u6A21\u578B\u540E\uFF0C\u6027\u80FD\u6D4B\u8BD5\u8BBE\u8BA1\u4EBA\u5458\u5F80\u5F80\u8FD8\u4F1A\u5728\u6B64\u57FA\u7840\u4E0A\u52A0\u5165\u4E00\u5B9A\u7684\u8D1F\u8F7D\u5197\u4F59\uFF0C\u6BD4\u5982\u5728\u5CF0\u503C\u7684\u57FA\u7840\u4E0A\u518D\u989D\u5916\u653E\u5927 20%\uFF0C\u4EE5\u589E\u5F3A\u7CFB\u7EDF\u4E0A\u7EBF\u540E\u7A33\u5B9A\u8FD0\u884C\u7684\u4FE1\u5FC3\u3002</p><p>\u901A\u8FC7\u4E0A\u9762\u8FD9\u4E2A\u5206\u6790\u8FC7\u7A0B\uFF0C\u4F60\u53EF\u4EE5\u8BA4\u8BC6\u5230\uFF0C\u6027\u80FD\u6D4B\u8BD5\u9700\u6C42\u7684\u5B9A\u4E49\u4E0E\u8BA1\u5212\u975E\u5E38\u590D\u6742\uFF0C\u7275\u6D89\u5230\u9879\u76EE\u7684\u65B9\u65B9\u9762\u9762\uFF0C\u4E0D\u53EF\u80FD\u901A\u8FC7\u9605\u8BFB\u4E00\u4E24\u7BC7\u6587\u7AE0\u5C31\u5FEB\u901F\u638C\u63E1\u8FD9\u4E00\u6280\u80FD\uFF0C\u9700\u8981\u4E0D\u65AD\u5730\u6C89\u6DC0\u5728\u5B9E\u6218\u4E2D\u83B7\u5F97\u7684\u7ECF\u9A8C\u3002</p><p>\u5236\u8BA2\u4E86\u6027\u80FD\u6D4B\u8BD5\u8BA1\u5212\u540E\uFF0C\u63A5\u4E0B\u6765\u4F60\u5C31\u9700\u8981\u6839\u636E\u6027\u80FD\u8BA1\u5212\u4E2D\u6D89\u53CA\u7684\u7528\u6237\u4E1A\u52A1\u64CD\u4F5C\u6765\u5F00\u53D1\u6027\u80FD\u6D4B\u8BD5\u7684\u811A\u672C\u4E86\u3002\u6BD4\u5982\uFF0C\u524D\u9762\u63D0\u5230\u201C20%\u7684\u7528\u6237\u5728\u505A\u767B\u5F55\u64CD\u4F5C\uFF0C30%\u7684\u7528\u6237\u5728\u505A\u8BA2\u5355\u64CD\u4F5C\uFF0C\u5269\u4E0B 50%\u7684\u7528\u6237\u5728\u505A\u641C\u7D22\u64CD\u4F5C\u201D\uFF0C\u63A5\u4E0B\u6765\u4F60\u9700\u8981\u5206\u522B\u5F00\u53D1\u201C\u7528\u6237\u767B\u5F55\u201D\u201C\u4E0B\u8BA2\u5355\u201D\u548C\u201C\u641C\u7D22\u201D\u8FD9\u4E09\u4E2A\u865A\u62DF\u7528\u6237\u811A\u672C\u3002</p><p>\u5728 LoadRunner \u4E2D\uFF0C\u5F00\u53D1\u865A\u62DF\u7528\u6237\u811A\u672C\u7684\u5DE5\u4F5C\u4E3B\u8981\u662F\u57FA\u4E8E\u5F55\u5236\u540E\u518D\u4FEE\u6539\u7684\u65B9\u5F0F\u5B8C\u6210\u7684\u3002\u5176\u4E2D\uFF0C\u5F55\u5236\u7531 Virtual UserGenerator \u57FA\u4E8E\u534F\u8BAE\u5B8C\u6210\uFF0C\u5F55\u5236\u540E\u7684\u4FEE\u6539\u4E3B\u8981\u662F\u5B9E\u73B0\u53C2\u6570\u5316\u3001\u5EFA\u7ACB\u5173\u8054\u3001\u5EFA\u7ACB\u4E8B\u52A1\u3001\u52A0\u5165\u5FC5\u8981\u7684\u68C0\u67E5\u70B9\u4EE5\u53CA\u52A0\u5165\u601D\u8003\u65F6\u95F4\u3002</p><p>\u6240\u4EE5\uFF0C\u6211\u4F1A\u5728\u4E0B\u6B21\u5206\u4EAB\u65F6\uFF0C\u548C\u4F60\u8BE6\u7EC6\u8BA8\u8BBA\u8FD9\u56DB\u90E8\u5206\u5DE5\u4F5C\u7684\u4F5C\u7528\uFF0C\u4EE5\u53CA\u5177\u4F53\u5982\u4F55\u5B8C\u6210\u3002\u540C\u65F6\uFF0C\u6211\u8FD8\u4F1A\u548C\u4F60\u5206\u4EAB\uFF0C\u4F01\u4E1A\u7EA7\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u540E\u56DB\u4E2A\u9636\u6BB5\u5982\u4F55\u5B9E\u73B0\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u4ECA\u5929\u6211\u548C\u4F60\u8BA8\u8BBA\u7684\u4E3B\u9898\u662F\uFF0C\u5982\u4F55\u57FA\u4E8E LoadRunner \u5B9E\u73B0\u4F01\u4E1A\u7EA7\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u3002</p><p>\u9996\u5148\uFF0C\u6211\u7528\u4E00\u4E2A\u201C\u4EBA\u8089\u201D\u6D4B\u8BD5\u7684\u6D41\u7A0B\u7C7B\u6BD4\uFF0C\u4E3A\u4F60\u4ECB\u7ECD\u4E86 LoadRunner \u8FD9\u4E2A\u5DE5\u5177\u7684\u57FA\u672C\u539F\u7406\uFF0C\u5E76\u5206\u6790\u4E86 Virtual User Generator\u3001Controller\uFF08\u5185\u542B Load Generator \u6A21\u5757\uFF09\uFF0C\u4EE5\u53CA Analysis \u8FD9 3 \u4E2A\u6A21\u5757\u7684\u529F\u80FD\u3002</p><p>\u7136\u540E\uFF0C\u4ECE\u5B8F\u89C2\u89D2\u5EA6\uFF0C\u6211\u628A\u6574\u4E2A\u6027\u80FD\u6D4B\u8BD5\u8FC7\u7A0B\u5212\u5206\u6210\u4E86\u4E94\u4E2A\u9636\u6BB5\uFF1A\u6027\u80FD\u9700\u6C42\u6536\u96C6\u4EE5\u53CA\u8D1F\u8F7D\u8BA1\u5212\u5236\u5B9A\u3001\u5F55\u5236\u5E76\u589E\u5F3A\u865A\u62DF\u7528\u6237\u811A\u672C\u3001\u521B\u5EFA\u5E76\u5B9A\u4E49\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u3001\u6267\u884C\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\uFF0C\u4EE5\u53CA\u5206\u6790\u6D4B\u8BD5\u62A5\u544A\u3002</p><p>\u5728\u6211\u770B\u6765\uFF0C\u8FD9\u4E94\u4E2A\u9636\u6BB5\u6700\u96BE\u7684\u4E24\u90E8\u5206\u5DE5\u4F5C\u5206\u522B\u662F\uFF1A\u660E\u786E\u5177\u4F53\u7684\u6027\u80FD\u6D4B\u8BD5\u9700\u6C42\uFF0C\u4EE5\u53CA\u6D4B\u8BD5\u7ED3\u679C\u5206\u6790\u4E0E\u6027\u80FD\u95EE\u9898\u5B9A\u4F4D\u3002\u56E0\u4E3A\u8FD9\u4E24\u90E8\u5206\u5DE5\u4F5C\uFF0C\u8981\u5927\u91CF\u4F9D\u8D56\u4E8E\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u7684\u80FD\u529B\u4EE5\u53CA\u7ECF\u9A8C\u79EF\u7D2F\u3002\u6240\u4EE5\uFF0C\u5C31\u50CF\u4E00\u540D\u4F18\u79C0\u7684\u533B\u751F\u4E00\u6837\uFF0C\u4F18\u79C0\u7684\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\uFF0C\u9700\u8981\u5728\u5B9E\u9645\u7684\u5DE5\u7A0B\u9879\u76EE\u4E2D\u4E0D\u65AD\u79EF\u7D2F\u548C\u603B\u7ED3\u7ECF\u9A8C\u3002</p><p>\u6700\u540E\uFF0C\u6211\u4EE5\u524D\u9762\u6587\u7AE0\u63D0\u5230\u8FC7\u7684\u4F53\u68C0\u4E2D\u5FC3\u4E3A\u4F8B\uFF0C\u548C\u4F60\u8BE6\u7EC6\u8BA8\u8BBA\u4E86\u5982\u4F55\u6536\u96C6\u6027\u80FD\u9700\u6C42\uFF0C\u4EE5\u53CA\u5236\u5B9A\u8D1F\u8F7D\u8BA1\u5212\u7684\u5185\u5BB9\u3002\u6211\u4E5F\u89E3\u91CA\u4E86\u4E3A\u4EC0\u4E48\u6027\u80FD\u6D4B\u8BD5\u7684\u9700\u6C42\u4E0D\u80FD\u76F4\u63A5\u4ECE\u4EA7\u54C1\u7ECF\u7406\u90A3\u91CC\u83B7\u5F97\uFF1A\u56E0\u4E3A\u4EA7\u54C1\u7ECF\u7406\u5B9A\u4E49\u7684\u6027\u80FD\u9700\u6C42\u5C42\u6B21\u6BD4\u8F83\u9AD8\u3001\u6BD4\u8F83\u62BD\u8C61\uFF0C\u8981\u843D\u5B9E\u5230\u5B9E\u9645\u53EF\u6267\u884C\u7684\u6027\u80FD\u6D4B\u8BD5\u9700\u6C42\u5F80\u5F80\u9700\u8981\u5206\u6790\u548C\u7EC6\u5316\u3002\u8FD9\u4E5F\u662F\u4E3A\u4EC0\u4E48\u83B7\u53D6\u5177\u4F53\u7684\u6027\u80FD\u9700\u6C42\u6BD4\u8F83\u96BE\u7684\u4E00\u4E2A\u539F\u56E0\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u4F60\u5728\u5B9E\u9645\u5DE5\u4F5C\u4E2D\uFF0C\u662F\u5982\u4F55\u83B7\u53D6\u5E76\u7EC6\u5316\u6027\u80FD\u6D4B\u8BD5\u9700\u6C42\u7684\u5462\uFF1F</p>',64);function e(t,a){return p}var s=r(o,[["render",e],["__file","32.html.vue"]]);export{s as default};
